import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { useTheme } from './contexts/ThemeContext';
import AuthPage from './pages/AuthPage';
import DashboardPage from './pages/DashboardPage';
import LandingPage from './pages/LandingPage';
import NotFoundPage from './pages/NotFoundPage';
import { User, ThemeStyle, ThemeMode, Notification, Post, Comment, GlobalNotification } from './types';
import { NotificationProvider } from './contexts/NotificationContext';
import useLocalStorage from './hooks/useLocalStorage';
import { MOCK_USERS } from './data/users';
import { MOCK_POSTS } from './data/posts';
import { auth, googleProvider, githubProvider, firebaseConfig } from './firebaseConfig';
import { 
  onAuthStateChanged, 
  createUserWithEmailAndPassword, 
  sendEmailVerification,
  signInWithEmailAndPassword,
  signInWithPopup,
  signOut,
  User as FirebaseUser,
  getAuth,
  deleteUser as deleteFirebaseUser,
  setPersistence,
  browserSessionPersistence,
  browserLocalPersistence,
  sendSignInLinkToEmail,
  EmailAuthProvider,
  reauthenticateWithCredential,
  verifyBeforeUpdateEmail,
  onIdTokenChanged,
  sendPasswordResetEmail,
  updateProfile
} from 'firebase/auth';
import { 
    getAllUsers, addUser, updateUser, getPosts, addPost, updatePost, deletePost, likePost, addCommentToPost, getSupabase, 
    getUserByFirebaseUid, isUsingMockData, addActivityLog, deleteUser as deleteSupabaseUser, sendMagicLinkWithBrevo,
    getNotificationsForUser, addNotificationToDb, updateNotificationInDb, deleteNotificationFromDb, deleteAllNotificationsForUser, markAllNotificationsAsReadForUser,
    sendGlobalNotifications, sanitizePost
} from './services/database';
import { sendWelcomeEmail } from './services/emailService';
import XCircleIcon from './components/icons/XCircleIcon';
import { useAuthSync } from './hooks/useAuthSync';
import MicrochipLoader from './components/MicrochipLoader';
import WelcomeAnimation from './components/WelcomeAnimation';
import DeletionAnimation from './components/DeletionAnimation';
import NotificationContainer from './components/NotificationContainer';
import { verifyTOTP } from './utils/totp';

// Declare custom element for TypeScript
declare global {
  namespace JSX {
    interface IntrinsicElements {
      'elevenlabs-convai': React.DetailedHTMLProps<React.HTMLAttributes<HTMLElement>, HTMLElement> & { 'agent-id': string };
    }
