                      ]
                   });
                }
                break;
           default:
              if (notif.type) {
                 addNotification({
                  ...commonProps,
                  title: notif.title || 'Notification',
                  message: notif.message,
                  type: 'info',
                  sourceType: notif.type as any,
                 });
